/**
 * Fetch email content, enriching each email with metadata from the provided map.
 * Supports two providers via opts.emailProvider:
 *   - 'content-fetcher' (default): calls content-fetcher service
 *   - 'email-service': calls email-service API with compat format
 *
 * @param {string[]} messageIds - message IDs to fetch
 * @param {Map} metaByMessageId - Map<messageId, { EMAIL_METADATA_ID, THREAD_ID, PREVIOUS_AI_SUMMARY? }>
 * @param {object} opts
 * @param {string} opts.contentFetcherUrl - base URL for content fetcher
 * @param {string} [opts.emailServiceUrl] - base URL for email-service
 * @param {string} [opts.emailProvider='content-fetcher'] - which provider to use
 * @param {string} opts.userId - user ID for the request
 * @param {string} [opts.syncStateId] - optional sync state ID
 * @param {number} opts.chunkSize - messages per request
 * @param {number} opts.fetchTimeoutMs - timeout per request
 * @param {number} [opts.maxRetries=3] - retries per chunk
 * @param {string} [opts.format] - 'metadata' (headers only) or undefined (full content)
 * @returns {Promise<object[]>} enriched email objects
 */
async function fetchEmails(messageIds, metaByMessageId, opts) {
  if (opts.emailProvider === 'email-service') {
    return fetchEmailsFromService(messageIds, metaByMessageId, opts)
  }
  const {
    contentFetcherUrl,
    userId,
    syncStateId,
    chunkSize,
    fetchTimeoutMs,
    maxRetries = DEFAULT_MAX_RETRIES,
    format,
  } = opts;

  if (!messageIds || messageIds.length === 0) {
    return []
  }

  const allEmails = [];

  const fetchStart = Date.now();
  let totalChunks = 0;

  for (let i = 0; i < messageIds.length; i += chunkSize) {
    const chunk = messageIds.slice(i, i + chunkSize);
    const chunkIndex = Math.floor(i / chunkSize) + 1;
    totalChunks++;
    let pendingIds = [...chunk];

    for (let attempt = 0; attempt < maxRetries && pendingIds.length > 0; attempt++) {
      try {
        const { signal, clear } = withTimeout(fetchTimeoutMs);
        try {
          const body = {
            userId,
            ...(syncStateId ? { syncStateId } : {}),
            messageIds: pendingIds,
            ...(format ? { format } : {}),
          };

          const resp = await fetch(`${contentFetcherUrl}/email-content/fetch`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(body),
            signal,
          });
          clear();

          // Handle 429 rate limiting
          if (resp.status === 429) {
            const retryBody = await resp.json().catch(() => ({}));
            const retryAfterMs = retryBody.retryAfterMs || backoffMs(attempt, { base: 1000 });
            console.log(
              `[email-client] 429 rate limited, waiting ${retryAfterMs}ms ` +
                `(chunk ${chunkIndex}, attempt ${attempt + 1}/${maxRetries})`,
            );
            await sleep(retryAfterMs);
            continue
          }

          // Handle 502 — try to parse per-messageId errors
          if (resp.status === 502) {
            let failedIds = pendingIds; // default: retry all
            try {
              const errBody = await resp.json();
              if (errBody.errors && Array.isArray(errBody.errors)) {
                failedIds = errBody.errors.map((e) => e.messageId).filter(Boolean);
                if (failedIds.length === 0) failedIds = pendingIds;
              }
            } catch {
              // Non-JSON body — retry all pendingIds
            }
            pendingIds = failedIds;
            console.log(
              `[email-client] 502 — ${pendingIds.length} messageIds to retry ` +
                `(chunk ${chunkIndex}, attempt ${attempt + 1}/${maxRetries})`,
            );
            if (attempt < maxRetries - 1) {
              const waitMs = backoffMs(attempt, { base: 1000 });
              await sleep(waitMs);
            }
            continue
          }

          if (!resp.ok) {
            throw new Error(`HTTP ${resp.status}: ${await resp.text()}`)
          }

          const result = await resp.json();

          // Handle 207 partial success
          if (resp.status === 207) {
            const successEmails = result.data || [];
            const errors = result.errors || [];
            enrichAndCollect(successEmails, allEmails, metaByMessageId);
            const failedIds = errors.map((e) => e.messageId).filter(Boolean);
            if (failedIds.length > 0) {
              pendingIds = failedIds;
              console.log(
                `[email-client] 207 partial — ${successEmails.length} ok, ${failedIds.length} failed ` +
                  `(chunk ${chunkIndex}, attempt ${attempt + 1}/${maxRetries})`,
              );
              if (attempt < maxRetries - 1) {
                const waitMs = backoffMs(attempt, { base: 1000 });
                await sleep(waitMs);
              }
              continue
            }
            // No failures — done with this chunk
            pendingIds = [];
            continue
          }

          // 200 success — all messages in response
          const emails = result.data || result;
          enrichAndCollect(emails, allEmails, metaByMessageId);
          pendingIds = [];
        } catch (err) {
          clear();
          throw err
        }
      } catch (err) {
        console.log(
          `[email-client] chunk ${chunkIndex} fetch failed ` +
            `(attempt ${attempt + 1}/${maxRetries}): ${err.message}`,
        );

        // If not the last attempt, wait with exponential backoff before retry
        if (attempt < maxRetries - 1) {
          const waitMs = backoffMs(attempt, { base: 1000 });
          await sleep(waitMs);
        }
      }
    }
  }

  if (allEmails.length === 0 && messageIds.length > 0) {
    throw new Error(`All content fetches failed — 0/${messageIds.length} emails retrieved`)
  }

  const fetchTotalMs = Date.now() - fetchStart;
  console.log(
    `[email-client] fetch done: ${allEmails.length}/${messageIds.length} emails, ${totalChunks} chunks, ${fetchTotalMs}ms`,
  );

  return allEmails
}

var systemTemplate = "You are an email classifier for a content creator's inbox. Identify brand deals and business opportunities. Return valid JSON only — no markdown, no explanation, no code fences.\n\n# Creator Context\n\nThe user message may specify the creator's email. If provided, use it to distinguish inbound (to creator) from outbound (from creator) emails. If not provided, infer from exchange patterns.\n\n# Classification Rules\n\n**Priority: maximum recall.** If there is a 20% or greater chance something is a brand deal, classify as is_deal: true. When uncertain, use category \"low_confidence\". Missing a real deal costs thousands; a false positive costs 2 seconds to dismiss.\n\n## What IS a deal\n\nA brand, company, agency, platform, or fellow creator wants to work with this creator for their audience, content, reach, or influence. Includes: sponsorships, paid collaborations, product seeding/gifting, affiliate offers, ambassador programs, creator-to-creator collabs, event appearances, paid placements, content licensing, talent agency outreach. Classify regardless of status (new, active, declined, completed, suspicious).\n\n**Strong signals** (any one = is_deal: true): sender from brand/agency/PR firm, mentions sponsorship/collaboration/partnership/campaign, references compensation or budget, proposes deliverables or timeline, references creator's audience/reach, sender has partnership title, requests rate card, mentions exclusivity/licensing, originates from influencer marketing platform.\n\n**Weak signals** (alone = low_confidence): generic \"opportunity\" language, PR press release without ask, event invite without compensation details, vague \"collab\" subject from corporate domain, follow-up referencing unseen conversation.\n\n## What is NOT a deal\n\nInvestor/fundraising conversations, legal/accounting services, internal team discussions, automated notifications (YouTube/Instagram/TikTok/GMass/newsletters), surveys/feedback requests, SaaS pitches (unless proposing to sponsor creator's content), personal messages, calendar-only threads, shipping/order confirmations, password resets, billing notifications, social media alerts, traditional job recruitment, charity requests (unless paid partnership).\n\n# Output Schema\n\nReturn a JSON array with exactly one object per THREAD_ID_INDEX. The array MUST have the same number of elements as threads provided.\n\nFields per object:\n\n- **thread_index** (integer, required): The THREAD_ID_INDEX from the input (1-based)\n- **is_deal** (boolean, required): true if this is or might be a deal\n- **is_english** (boolean, required): true if primary language is English\n- **language** (string or null): ISO 639-1 code when is_english is false, otherwise null\n- **ai_score** (integer 1-10, required): Creator attention priority. 9-10: urgent, respond today. 7-8: high-value, act soon. 5-6: active, no deadline. 3-4: low priority. 1-2: no action needed.\n- **category** (string or null): Required when is_deal is true. One of: \"new\", \"in_progress\", \"completed\", \"not_interested\", \"likely_scam\", \"low_confidence\". Null when is_deal is false.\n- **likely_scam** (boolean, required): true if suspicious patterns detected\n- **ai_insight** (string, required): One-line summary of the opportunity or why it's not a deal\n- **ai_summary** (string, required, max 1000 chars): Context memo for the next AI evaluation (see guidelines below)\n- **main_contact** (object or null): The primary EXTERNAL person relevant to the deal — must NOT be the creator or match the creator's email. If the most relevant contact is the creator, use the next best external contact from the thread instead (e.g. the sender of an inbound deal email, or a CC'd brand representative). Fields: name, email, company, title, phone_number (all string or null). Null when is_deal is false or when no external contact can be identified in the thread.\n- **deal_brand** (string or null): Brand/company name. Null when is_deal is false.\n- **deal_type** (string or null): One of: \"brand_collaboration\", \"sponsorship\", \"affiliate\", \"product_seeding\", \"ambassador\", \"content_partnership\", \"paid_placement\", \"other_business\". Null when is_deal is false.\n- **deal_name** (string or null): Short descriptive name. Null when is_deal is false.\n- **deal_value** (number or null): Only if compensation explicitly mentioned. Null otherwise.\n- **deal_currency** (string or null): ISO 4217 code when deal_value present. Null otherwise.\n\n# AI Summary Guidelines\n\nThe ai_summary is the ONLY context the next classifier will have when new emails arrive. Write it as a factual briefing:\n\n- **Who**: Main contact's full name, email, title, company. Other relevant participants.\n- **What**: Specific proposal, deliverables, content format requested\n- **Status**: Current state of conversation or negotiation\n- **Terms**: Exact compensation figures, rates, budget, currency if mentioned\n- **Dates**: Deadlines, campaign dates, response-by dates\n- **Red flags**: Anything suspicious or noteworthy\n\n# Previous AI Summary\n\nWhen a thread includes PREVIOUS_AI_SUMMARY, it reflects a prior evaluation with fewer emails. New emails may change the classification. Re-evaluate fully — use the prior summary as background context only.\n\n# Examples\n\n## Deal example\n\nThread: Sarah Kim (sarah@beautybrandx.com, Partnerships Manager, Beauty Brand X) proposes $2,500 sponsored YouTube review with 60-day exclusivity.\n\n```json\n{\n  \"thread_index\": 1,\n  \"is_deal\": true,\n  \"is_english\": true,\n  \"ai_score\": 8,\n  \"category\": \"new\",\n  \"likely_scam\": false,\n  \"ai_insight\": \"Beauty Brand X offers $2.5K for sponsored YouTube review\",\n  \"ai_summary\": \"Sarah Kim (sarah@beautybrandx.com, Partnerships Manager, Beauty Brand X) proposes $2,500 sponsored dedicated YouTube video reviewing new serum line. 60-day exclusivity. Requested creator's rate card. Status: initial outreach, awaiting creator response.\",\n  \"main_contact\": {\n    \"name\": \"Sarah Kim\",\n    \"email\": \"sarah@beautybrandx.com\",\n    \"company\": \"Beauty Brand X\",\n    \"title\": \"Partnerships Manager\",\n    \"phone_number\": null\n  },\n  \"deal_brand\": \"Beauty Brand X\",\n  \"deal_type\": \"sponsorship\",\n  \"deal_name\": \"Beauty Brand X YouTube Review\",\n  \"deal_value\": 2500,\n  \"deal_currency\": \"USD\"\n}\n```\n\n## Non-deal example\n\nThread: noreply@youtube.com sends 100K subscriber milestone notification.\n\n```json\n{\n  \"thread_index\": 2,\n  \"is_deal\": false,\n  \"is_english\": true,\n  \"ai_score\": 1,\n  \"category\": null,\n  \"likely_scam\": false,\n  \"ai_insight\": \"YouTube milestone notification\",\n  \"ai_summary\": \"Automated YouTube notification about 100K subscriber milestone. No deal content.\",\n  \"main_contact\": null,\n  \"deal_brand\": null,\n  \"deal_type\": null,\n  \"deal_name\": null,\n  \"deal_value\": null,\n  \"deal_currency\": null\n}\n```\n\nOnly classify the threads in the user message. Do NOT classify the examples above.\n\n# Final Rules\n\n1. Return ONLY a valid JSON array\n2. One object per THREAD_ID_INDEX — array length MUST match thread count\n3. When is_deal is false: set category, deal_brand, deal_type, deal_name, deal_value, deal_currency, and main_contact to null\n4. When is_deal is true: deal_type and deal_name are required. deal_brand required when identifiable.\n5. main_contact must be an EXTERNAL person — NEVER the creator. If the creator's email is provided, do NOT use that email in main_contact. Instead, pick the best non-creator contact from the thread (e.g. the inbound sender or a CC'd brand rep). Only set main_contact to null if no external contact exists in the thread at all.\n6. ai_summary is always required for every thread\n7. When uncertain: default to is_deal: true with category \"low_confidence\"\n";

var classificationInstructions = "Classify the email threads below. Return one JSON object per thread in a JSON array.\n\n# Threads to Classify\n\n{{THREAD_DATA}}\n";

// --- Prompt building ---

function groupByThread(emails) {
  const threads = {};
  for (const email of emails) {
    const threadId = email.threadId || email.id;
    if (!threads[threadId]) threads[threadId] = [];
    threads[threadId].push(email);
  }
  return threads
}

function buildThreadData(emails) {
  const threads = groupByThread(emails);
  const parts = [];
  const threadOrder = [];
  let threadIndex = 0;

  for (const [threadId, threadEmails] of Object.entries(threads)) {
    threadIndex++;
    threadOrder.push(threadId);
    let section = `THREAD_ID_INDEX: ${threadIndex}\n`;
    section += `MODE: FULL_THREAD\n`;
    section += `Message Count: ${threadEmails.length}\n`;

    const previousSummary = threadEmails[0].previousAiSummary;
    section += `PREVIOUS_AI_SUMMARY: ${previousSummary || 'None'}\n\n`;

    threadEmails.forEach((email, i) => {
      const from = getHeader(email, 'from');
      const date = getHeader(email, 'date');
      const subject = getHeader(email, 'subject');
      section += `[Message ${i + 1}]\n`;
      section += `From: ${from}\n`;
      section += `Date: ${date}\n`;
      section += `Subject: ${subject}\n\n`;
      const rawBody = email.body || email.replyBody || '';
      const body = sanitizeEmailBody(rawBody) || '[no body]';
      section += `${body}\n\n`;
      if (rawBody.length > 5000) {
        console.log(
          `[ai-prompt] thread=${threadId} msg=${i + 1}: rawBody=${rawBody.length} chars → sanitized=${body.length} chars`,
        );
      }
    });

    section += '===\n';
    parts.push(section);
  }

  return { text: parts.join('\n'), threadOrder }
}

function buildPrompt(emails, { systemOverride, userOverride, creatorEmail } = {}) {
  const { text: threadData, threadOrder } = buildThreadData(emails);

  const systemPrompt = (systemOverride || systemTemplate).trim();

  const creatorLine = creatorEmail ? `Creator email: ${creatorEmail}\n\n` : '';

  const userPrompt = (userOverride || classificationInstructions)
    .replace('{{THREAD_DATA}}', creatorLine + threadData)
    .trim();

  console.log(
    `[ai-prompt] ${emails.length} emails, ${threadOrder.length} threads, ` +
      `system=${systemPrompt.length} chars, user=${userPrompt.length} chars, ` +
      `threadData=${threadData.length} chars`,
  );

  return { systemPrompt, userPrompt, threadOrder }
}

// --- Constants ---
const AI_REQUEST_TIMEOUT_MS = 240000;
const AI_RETRY_DELAY_MS = 2000;
const MAX_HTTP_RETRIES = 3;
const MAX_TOKENS = 20480;

// --- Valid categories and deal types for validation ---
const VALID_CATEGORIES = new Set([
  'new',
  'in_progress',
  'completed',
  'not_interested',
  'likely_scam',
  'low_confidence',
]);
const VALID_DEAL_TYPES = new Set([
  'brand_collaboration',
  'sponsorship',
  'affiliate',
  'product_seeding',
  'ambassador',
  'content_partnership',
  'paid_placement',
  'other_business',
]);

// --- AI client ---

/**
 * Call a model with HTTP retries + exponential backoff.
 * Returns { content, usage } or throws on total failure.
 *
 * @param {string} model - Model ID
 * @param {Array} messages - Chat messages
 * @param {Object} opts - { temperature, apiUrl, apiKey }
 */
const MAX_RATE_LIMIT_WAITS = 10;

async function callModel(model, messages, { temperature = 0, apiUrl, apiKey } = {}) {
  let lastError;
  let rateLimitWaits = 0;
  for (let attempt = 1; attempt <= MAX_HTTP_RETRIES; attempt++) {
    try {
      console.log(`[ai-client] ${model} (attempt ${attempt}/${MAX_HTTP_RETRIES})`);
      const resp = await fetch(apiUrl, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${apiKey}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          model,
          messages,
          temperature,
          max_tokens: MAX_TOKENS,
          response_format: { type: 'json_object' },
        }),
        signal: AbortSignal.timeout(AI_REQUEST_TIMEOUT_MS),
      });

      if (!resp.ok) {
        const errBody = await resp.text().catch(() => '');
        lastError = new Error(`HTTP ${resp.status}: ${errBody.substring(0, 200)}`);
        console.log(`[ai-client] ${model} HTTP ${resp.status}: ${errBody.substring(0, 200)}`);

        // 429: respect Retry-After or wait 5s, don't consume retry budget
        if (resp.status === 429 && rateLimitWaits < MAX_RATE_LIMIT_WAITS) {
          rateLimitWaits++;
          const retryAfter = parseInt(resp.headers.get('retry-after') || '5', 10) * 1000;
          console.log(
            `[ai-client] ${model} rate limited (${rateLimitWaits}/${MAX_RATE_LIMIT_WAITS}), waiting ${retryAfter}ms`,
          );
          await sleep(retryAfter);
          attempt--; // don't consume attempt
          continue
        }

        if (attempt < MAX_HTTP_RETRIES) {
          await sleep(backoffMs(attempt - 1, { base: AI_RETRY_DELAY_MS }));
          continue
        }
        throw lastError
      }

      const result = await resp.json();
      const content = result.choices?.[0]?.message?.content;
      if (!content) throw new Error('Empty response from model')

      const usage = result.usage || {};
      return { content, usage }
    } catch (err) {
      lastError = err;
      if (attempt < MAX_HTTP_RETRIES) {
        const delay = backoffMs(attempt - 1, { base: AI_RETRY_DELAY_MS });
        console.log(
          `[ai-client] ${model} attempt ${attempt} failed: ${err.message}, retrying in ${delay}ms`,
        );
        await sleep(delay);
      }
    }
  }
  throw lastError || new Error(`${model} failed after ${MAX_HTTP_RETRIES} attempts`)
}

/**
 * Layer 1: Local JSON repair — strip fences, extract array, unwrap objects, coerce schema.
 * @param {string} raw — raw AI response
 * @param {string[]} [threadOrder] — maps thread_index (1-based) to thread_id
 */
function parseAndValidate(raw, threadOrder) {
  let content = raw.trim();

  // Strip markdown fences
  content = content
    .replace(/^```(?:json)?\s*\n?/gi, '')
    .replace(/\n?```\s*$/gi, '')
    .trim();

  // Try to find JSON array in mixed output
  if (!content.startsWith('[')) {
    const arrayStart = content.indexOf('[');
    const arrayEnd = content.lastIndexOf(']');
    if (arrayStart !== -1 && arrayEnd > arrayStart) {
      content = content.slice(arrayStart, arrayEnd + 1);
    }
  }

  // Parse
  let parsed;
  try {
    parsed = JSON.parse(content);
  } catch {
    // Try to extract from wrapper object like {"results": [...]}
    const objStart = content.indexOf('{');
    const objEnd = content.lastIndexOf('}');
    if (objStart !== -1 && objEnd > objStart) {
      const obj = JSON.parse(content.slice(objStart, objEnd + 1));
      const arrays = Object.values(obj).filter(Array.isArray);
      if (arrays.length === 1) {
        parsed = arrays[0];
      } else {
        throw new Error('Cannot extract JSON array from response')
      }
    } else {
      throw new Error('No valid JSON found in response')
    }
  }

  // Unwrap if object with single array property
  if (!Array.isArray(parsed)) {
    const arrays = Object.values(parsed).filter(Array.isArray);
    if (arrays.length === 1) {
      parsed = arrays[0];
    } else {
      throw new Error('Response is not a JSON array')
    }
  }

  // Schema validation and coercion
  return parsed.map((r) => ({
    thread_id:
      threadOrder && r.thread_index != null
        ? threadOrder[Math.max(0, Number(r.thread_index) - 1)] || String(r.thread_id || '')
        : String(r.thread_id || ''),
    is_deal: Boolean(r.is_deal),
    is_english: r.is_english !== false,
    language: r.language || null,
    ai_score: Math.min(10, Math.max(1, Math.round(Number(r.ai_score) || 5))),
    category: r.is_deal ? (VALID_CATEGORIES.has(r.category) ? r.category : 'low_confidence') : null,
    likely_scam: Boolean(r.likely_scam) || r.category === 'likely_scam',
    ai_insight: String(r.ai_insight || ''),
    ai_summary: String(r.ai_summary || '').slice(0, 1000),
    main_contact: r.is_deal ? r.main_contact || null : null,
    deal_brand: r.is_deal ? r.deal_brand || null : null,
    deal_type: r.is_deal
      ? VALID_DEAL_TYPES.has(r.deal_type)
        ? r.deal_type
        : 'other_business'
      : null,
    deal_name: r.is_deal ? r.deal_name || null : null,
    deal_value: r.deal_value != null ? Number(r.deal_value) : null,
    deal_currency: r.deal_currency || null,
  }))
}

/**
 * Compute { mean, min, max, stddev } from an array of numbers.
 */
function aggregateStats(values) {
  if (values.length === 0) return { mean: 0, min: 0, max: 0, stddev: 0 }
  const mean = values.reduce((a, b) => a + b, 0) / values.length;
  const min = Math.min(...values);
  const max = Math.max(...values);
  const stddev = Math.sqrt(values.reduce((sum, v) => sum + (v - mean) ** 2, 0) / values.length);
  return {
    mean: +mean.toFixed(4),
    min: +min.toFixed(4),
    max: +max.toFixed(4),
    stddev: +stddev.toFixed(4),
  }
}

/**
 * Compute detection metrics (recall, precision, F2) across N runs.
 * Each run is an array of classification results from the AI.
 * Ground truth is the array from ground-truth.json.
 */
function computeDetectionMetrics(allRuns, groundTruth) {
  const recallPerRun = [];
  const precisionPerRun = [];
  const f2PerRun = [];

  for (const run of allRuns) {
    const resultMap = new Map(run.map((r) => [r.thread_id, r]));
    let tp = 0,
      fp = 0,
      fn = 0;

    for (const gt of groundTruth) {
      const result = resultMap.get(gt.id);
      if (!result) {
        if (gt.expected.is_deal) fn++;
        continue
      }
      if (gt.expected.is_deal && result.is_deal) tp++;
      else if (!gt.expected.is_deal && result.is_deal) fp++;
      else if (gt.expected.is_deal && !result.is_deal) fn++;
    }

    const recall = tp + fn > 0 ? tp / (tp + fn) : 1;
    const precision = tp + fp > 0 ? tp / (tp + fp) : 1;
    const f2 = precision + recall > 0 ? (5 * precision * recall) / (4 * precision + recall) : 0;

    recallPerRun.push(recall);
    precisionPerRun.push(precision);
    f2PerRun.push(f2);
  }

  return {
    recall: aggregateStats(recallPerRun),
    precision: aggregateStats(precisionPerRun),
    f2: aggregateStats(f2PerRun),
  }
}

/**
 * For deal threads correctly detected, was category correct?
 * Returns overall accuracy + per-category breakdown.
 */
function computeCategoryAccuracy(allRuns, groundTruth) {
  const accuracyPerRun = [];
  const dealThreads = groundTruth.filter((gt) => gt.expected.is_deal && gt.expected.category);

  // Collect per-category stats across all runs
  const categories = [...new Set(dealThreads.map((gt) => gt.expected.category))];
  const perCategoryCorrect = {};
  const perCategoryTotal = {};
  for (const cat of categories) {
    perCategoryCorrect[cat] = [];
    perCategoryTotal[cat] = 0;
  }

  for (const run of allRuns) {
    const resultMap = new Map(run.map((r) => [r.thread_id, r]));
    let correct = 0;
    let total = 0;
    const runCategoryCorrect = {};
    for (const cat of categories) runCategoryCorrect[cat] = 0;

    for (const gt of dealThreads) {
      const result = resultMap.get(gt.id);
      if (!result || !result.is_deal) continue
      total++;
      const expectedCat = gt.expected.category;
      if (result.category === expectedCat) {
        correct++;
        runCategoryCorrect[expectedCat]++;
      }
    }

    accuracyPerRun.push(total > 0 ? correct / total : 1);

    // Per-category accuracy for this run
    for (const cat of categories) {
      const catThreads = dealThreads.filter((gt) => gt.expected.category === cat);
      const catDetected = catThreads.filter((gt) => {
        const r = resultMap.get(gt.id);
        return r && r.is_deal
      }).length;
      perCategoryCorrect[cat].push(catDetected > 0 ? runCategoryCorrect[cat] / catDetected : 1);
      perCategoryTotal[cat] = catThreads.length;
    }
  }

  const perCategory = {};
  for (const cat of categories) {
    perCategory[cat] = {
      ...aggregateStats(perCategoryCorrect[cat]),
      ground_truth_count: perCategoryTotal[cat],
    };
  }

  return { accuracy: aggregateStats(accuracyPerRun), per_category: perCategory }
}

/**
 * For each thread, was ai_score within expected score_range?
 */
function computeScoreInRange(allRuns, groundTruth) {
  const ratePerRun = [];

  for (const run of allRuns) {
    const resultMap = new Map(run.map((r) => [r.thread_id, r]));
    let inRange = 0;
    let total = 0;

    for (const gt of groundTruth) {
      if (!gt.expected.score_range) continue
      const result = resultMap.get(gt.id);
      if (!result) continue
      total++;
      const [lo, hi] = gt.expected.score_range;
      if (result.ai_score >= lo && result.ai_score <= hi) inRange++;
    }

    ratePerRun.push(total > 0 ? inRange / total : 1);
  }

  return { in_range_rate: aggregateStats(ratePerRun) }
}

/**
 * For threads where expected.likely_scam = true, did AI flag likely_scam?
 */
function computeScamDetection(allRuns, groundTruth) {
  const scamThreads = groundTruth.filter((gt) => gt.expected.likely_scam);
  const accuracyPerRun = [];

  for (const run of allRuns) {
    const resultMap = new Map(run.map((r) => [r.thread_id, r]));
    let caught = 0;

    for (const gt of scamThreads) {
      const result = resultMap.get(gt.id);
      if (result && result.likely_scam) caught++;
    }

    accuracyPerRun.push(scamThreads.length > 0 ? caught / scamThreads.length : 1);
  }

  return {
    accuracy: aggregateStats(accuracyPerRun),
    total_scam_threads: scamThreads.length,
  }
}

/**
 * Per-thread breakdown: how many runs got each metric right.
 */
function computePerThread(allRuns, groundTruth) {
  return groundTruth.map((gt) => {
    let detectionCorrect = 0;
    let categoryCorrect = 0;
    let scoreInRange = 0;
    let scamCorrect = 0;

    for (const run of allRuns) {
      const result = run.find((r) => r.thread_id === gt.id);
      if (!result) continue

      // Detection
      if (result.is_deal === gt.expected.is_deal) detectionCorrect++;

      // Category (only for deals)
      if (gt.expected.is_deal && result.is_deal && gt.expected.category) {
        if (result.category === gt.expected.category) categoryCorrect++;
      }

      // Score range
      if (gt.expected.score_range) {
        const [lo, hi] = gt.expected.score_range;
        if (result.ai_score >= lo && result.ai_score <= hi) scoreInRange++;
      }

      // Scam
      if (result.likely_scam === gt.expected.likely_scam) scamCorrect++;
    }

    return {
      id: gt.id,
      description: gt.description,
      expected: gt.expected,
      detection_correct: detectionCorrect,
      category_correct: categoryCorrect,
      score_in_range: scoreInRange,
      scam_correct: scamCorrect,
      total_runs: allRuns.length,
    }
  })
}

/**
 * Compute JSON health metrics across runs.
 * Each run tracks: clean_parse, repaired, corrective_retry, failed
 */
function computeJsonHealth(jsonHealthPerRun) {
  const cleanRates = [];
  const repairedRates = [];
  const correctiveRates = [];
  let totalFailures = 0;

  for (const run of jsonHealthPerRun) {
    cleanRates.push(run.clean ? 1 : 0);
    repairedRates.push(run.repaired ? 1 : 0);
    correctiveRates.push(run.corrective_retry ? 1 : 0);
    if (run.failed) totalFailures++;
  }

  return {
    clean_parse_rate: aggregateStats(cleanRates),
    repaired_rate: aggregateStats(repairedRates),
    corrective_retry_rate: aggregateStats(correctiveRates),
    total_failures: totalFailures,
  }
}

