const PROMPT_BASE_URL = 'https://raw.githubusercontent.com/creatorland/dealsync-action';

async function fetchPromptsByHash(hash) {
  const [systemResp, userResp] = await Promise.all([
    fetch(`${PROMPT_BASE_URL}/${hash}/prompts/system.md`),
    fetch(`${PROMPT_BASE_URL}/${hash}/prompts/user.md`),
  ]);
  if (!systemResp.ok)
    throw new Error(`Failed to fetch system.md at ${hash}: HTTP ${systemResp.status}`)
  if (!userResp.ok) throw new Error(`Failed to fetch user.md at ${hash}: HTTP ${userResp.status}`)
  return {
    systemOverride: await systemResp.text(),
    userOverride: await userResp.text(),
  }
}

async function runEval() {
  const hyperbolicKey = coreExports.getInput('hyperbolic-key');
  const model = coreExports.getInput('primary-model') || 'Qwen/Qwen3-235B-A22B-Instruct-2507';
  const aiApiUrl = coreExports.getInput('ai-api-url') || 'https://api.hyperbolic.xyz/v1/chat/completions';
  const numRuns = parseInt(coreExports.getInput('runs') || '10', 10);
  const temperature = parseFloat(coreExports.getInput('temperature') || '0');
  const batchSize = parseInt(coreExports.getInput('batch-size') || '1', 10);
  const concurrency = parseInt(coreExports.getInput('concurrency') || '10', 10);
  const promptHash = coreExports.getInput('prompt-hash') || '';

  if (!hyperbolicKey) throw new Error('hyperbolic-key is required for eval')

  // Fetch prompts from a specific commit hash, or use bundled defaults
  let promptOverrides = {};
  if (promptHash) {
    console.log(`[eval] fetching prompts from commit ${promptHash}`);
    promptOverrides = await fetchPromptsByHash(promptHash);
  }

  // Filter out entries with empty bodies — AI can't classify without content
  const withBody = groundTruth.filter((gt) => gt.emails.some((e) => e.body && e.body.trim() !== ''));

  // Apply static filter rules (same as production pipeline)
  const filtered = [];
  const passedFilter = [];
  for (const gt of withBody) {
    if (isRejected(gt.emails[0])) {
      filtered.push(gt);
    } else {
      passedFilter.push(gt);
    }
  }

  const usableEntries = passedFilter;
  console.log(
    `[eval] model=${model} runs=${numRuns} threads=${usableEntries.length} batch_size=${batchSize} concurrency=${concurrency} prompt=${promptHash || 'bundled'}`,
  );
  console.log(
    `[eval] ground truth: ${groundTruth.length} total, ${groundTruth.length - withBody.length} empty body, ${filtered.length} static-filtered, ${usableEntries.length} to AI`,
  );

  const aiOpts = { apiUrl: aiApiUrl, apiKey: hyperbolicKey };
  const allRuns = [];
  const jsonHealthPerRun = [];
  let totalInputTokens = 0;
  let totalOutputTokens = 0;

  for (let run = 1; run <= numRuns; run++) {
    console.log(`[eval] --- run ${run}/${numRuns} ---`);

    // Split ground truth into batches (0 = all at once)
    const batches = [];
    if (batchSize > 0) {
      for (let i = 0; i < usableEntries.length; i += batchSize) {
        batches.push(usableEntries.slice(i, i + batchSize));
      }
    } else {
      batches.push(usableEntries);
    }

    const runHealth = {
      clean: 0,
      repaired: 0,
      corrective_retry: 0,
      failed: 0,
      total_batches: batches.length,
    };

    // Process batches with concurrency pool
    async function processBatch(batch, batchIdx) {
      const allEmails = batch.flatMap((gt) => gt.emails);
      const { systemPrompt, userPrompt } = buildPrompt(allEmails, promptOverrides);
      const messages = [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt },
      ];

      let rawContent = null;
      let usage = {};
      try {
        const result = await callModel(model, messages, { temperature, ...aiOpts });
        rawContent = result.content;
        usage = result.usage || {};
      } catch (apiErr) {
        console.log(`[eval] run ${run} batch ${batchIdx + 1} API failed: ${apiErr.message}`);
        return { threads: [], health: 'failed', usage }
      }

      // Layer 1: Local JSON repair
      try {
        const parsed = parseAndValidate(rawContent);
        return { threads: parsed, health: 'clean', usage }
      } catch (parseErr) {
        // Layer 2: Corrective retry
        try {
          const correctiveMessages = [
            ...messages,
            { role: 'assistant', content: rawContent },
            {
              role: 'user',
              content: `Your previous response could not be parsed as valid JSON.\n\nParse error:\n${parseErr.message}\n\nPlease return the corrected classification as a valid JSON array. Fix only the JSON formatting. Return ONLY the JSON array.`,
            },
          ];
          const corrected = await callModel(model, correctiveMessages, {
            temperature: 0,
            ...aiOpts,
          });
          const parsed = parseAndValidate(corrected.content);
          return { threads: parsed, health: 'corrective_retry', usage }
        } catch (correctiveErr) {
          console.log(
            `[eval] run ${run} batch ${batchIdx + 1}: corrective retry failed: ${correctiveErr.message}`,
          );
          return { threads: [], health: 'failed', usage }
        }
      }
    }

    // Run batches in parallel with concurrency limit
    const runThreads = [];
    const pending = [];
    let completed = 0;

    for (let b = 0; b < batches.length; b++) {
      const p = processBatch(batches[b], b).then((result) => {
        completed++;
        runThreads.push(...result.threads);
        runHealth[result.health]++;
        totalInputTokens += result.usage.prompt_tokens || 0;
        totalOutputTokens += result.usage.completion_tokens || 0;
        if (completed % 10 === 0 || completed === batches.length) {
          console.log(`[eval] run ${run}: ${completed}/${batches.length} batches done`);
        }
      });
      pending.push(p);

      // Enforce concurrency limit
      if (pending.length >= concurrency) {
        await Promise.race(pending);
        // Remove resolved promises
        for (let i = pending.length - 1; i >= 0; i--) {
          const settled = await Promise.race([pending[i].then(() => true), Promise.resolve(false)]);
          if (settled) pending.splice(i, 1);
        }
      }
    }
    await Promise.all(pending);

    console.log(
      `[eval] run ${run}: ${runThreads.length} threads (clean=${runHealth.clean} retry=${runHealth.corrective_retry} failed=${runHealth.failed})`,
    );

    if (runThreads.length > 0) {
      allRuns.push(runThreads);
    }
    jsonHealthPerRun.push({
      clean: runHealth.failed === 0 && runHealth.corrective_retry === 0,
      repaired: false,
      corrective_retry: runHealth.corrective_retry > 0,
      failed: runHealth.failed > 0,
      batch_count: runHealth.total_batches,
      batch_clean: runHealth.clean,
      batch_retry: runHealth.corrective_retry,
      batch_failed: runHealth.failed,
    });
  }

  if (allRuns.length === 0) {
    throw new Error(`All ${numRuns} runs failed — no valid results to compute metrics`)
  }

  // Compute metrics
  const detection = computeDetectionMetrics(allRuns, usableEntries);
  const categorization = computeCategoryAccuracy(allRuns, usableEntries);
  const urgencyScoring = computeScoreInRange(allRuns, usableEntries);
  const scamDetection = computeScamDetection(allRuns, usableEntries);
  const perThread = computePerThread(allRuns, usableEntries);
  const jsonHealth = computeJsonHealth(jsonHealthPerRun);

  const result = {
    model,
    temperature,
    batch_size: batchSize,
    prompt_hash: promptHash || 'bundled',
    runs: numRuns,
    successful_runs: allRuns.length,
    ground_truth_count: usableEntries.length,
    detection,
    categorization,
    urgency_scoring: urgencyScoring,
    scam_detection: scamDetection,
    json_health: jsonHealth,
    cost: {
      total_input_tokens: totalInputTokens,
      total_output_tokens: totalOutputTokens,
      avg_cost_per_thread:
        usableEntries.length > 0
          ? +(
              (totalInputTokens * 0.000001 + totalOutputTokens * 0.000002) /
              usableEntries.length
            ).toFixed(6)
          : 0,
    },
    per_thread: perThread,
  };

  console.log(
    `[eval] complete: recall=${detection.recall.mean} precision=${detection.precision.mean} f2=${detection.f2.mean} json_failures=${jsonHealth.total_failures}`,
  );
  return result
}

const THRESHOLDS = {
  recall: 0.95,
  precision: 0.4,
  consistency: 0.03,
};

function compareMetric(valA, valB) {
  const delta = +(valB - valA).toFixed(4);
  const winner = delta > 0.001 ? 'b' : delta < -1e-3 ? 'a' : 'tie';
  return { a: +valA.toFixed(4), b: +valB.toFixed(4), delta, winner }
}

async function runEvalCompare() {
  const resultAStr = coreExports.getInput('result-a');
  const resultBStr = coreExports.getInput('result-b');

  if (!resultAStr || !resultBStr) throw new Error('result-a and result-b are required')

  const a = JSON.parse(resultAStr);
  const b = JSON.parse(resultBStr);

  // Side-by-side metric comparison
  const comparison = {
    recall: compareMetric(a.detection.recall.mean, b.detection.recall.mean),
    precision: compareMetric(a.detection.precision.mean, b.detection.precision.mean),
    f2: compareMetric(a.detection.f2.mean, b.detection.f2.mean),
    category_accuracy: compareMetric(
      a.categorization.accuracy.mean,
      b.categorization.accuracy.mean,
    ),
    score_in_range: compareMetric(
      a.urgency_scoring.in_range_rate.mean,
      b.urgency_scoring.in_range_rate.mean,
    ),
    scam_detection: compareMetric(a.scam_detection.accuracy.mean, b.scam_detection.accuracy.mean),
  };

  // Per-category comparison
  const perCategoryComparison = {};
  const allCategories = new Set([
    ...Object.keys(a.categorization.per_category || {}),
    ...Object.keys(b.categorization.per_category || {}),
  ]);
  for (const cat of allCategories) {
    const aCat = a.categorization.per_category?.[cat];
    const bCat = b.categorization.per_category?.[cat];
    perCategoryComparison[cat] = {
      ...compareMetric(aCat?.mean ?? 0, bCat?.mean ?? 0),
      a_count: aCat?.ground_truth_count ?? 0,
      b_count: bCat?.ground_truth_count ?? 0,
    };
  }

  // JSON health comparison
  const jsonComparison = {
    clean_parse_rate: compareMetric(
      a.json_health.clean_parse_rate.mean,
      b.json_health.clean_parse_rate.mean,
    ),
    corrective_retry_rate: compareMetric(
      a.json_health.corrective_retry_rate.mean,
      b.json_health.corrective_retry_rate.mean,
    ),
    total_failures: { a: a.json_health.total_failures, b: b.json_health.total_failures },
  };

  // Cost comparison
  const costComparison = compareMetric(a.cost.avg_cost_per_thread, b.cost.avg_cost_per_thread);

  // Find regressions: threads A caught but B missed
  const aPerThread = new Map(a.per_thread.map((t) => [t.id, t]));
  const bPerThread = new Map(b.per_thread.map((t) => [t.id, t]));
  const newMissedDeals = [];
  const newMissedScams = [];
  const categoryRegressions = [];

  for (const [id, at] of aPerThread) {
    const bt = bPerThread.get(id);
    if (!bt) continue
    // A always caught it, B missed it at least once
    if (at.detection_correct === at.total_runs && bt.detection_correct < bt.total_runs) {
      if (at.expected.is_deal) newMissedDeals.push(id);
    }
    if (at.scam_correct === at.total_runs && bt.scam_correct < bt.total_runs) {
      newMissedScams.push(id);
    }
    if (at.category_correct > bt.category_correct) {
      categoryRegressions.push(id);
    }
  }

  // Pass/fail verdict
  const passFail = {
    b_recall_above_95: b.detection.recall.mean >= THRESHOLDS.recall,
    b_precision_above_40: b.detection.precision.mean >= THRESHOLDS.precision,
    b_f2_above_baseline: b.detection.f2.mean >= a.detection.f2.mean,
    b_consistency_within_3pct: b.detection.recall.stddev <= THRESHOLDS.consistency,
    no_new_missed_deals: newMissedDeals.length === 0,
    b_scam_no_regression: newMissedScams.length === 0,
    b_category_no_regression: b.categorization.accuracy.mean >= a.categorization.accuracy.mean,
  };
  passFail.verdict = Object.entries(passFail)
    .filter(([k]) => k !== 'verdict')
    .every(([, v]) => v === true)
    ? 'PASS'
    : 'FAIL';

  const result = {
    variant_a: { model: a.model, runs: a.runs, successful_runs: a.successful_runs },
    variant_b: { model: b.model, runs: b.runs, successful_runs: b.successful_runs },
    comparison,
    per_category: perCategoryComparison,
    json_health: jsonComparison,
    cost: costComparison,
    consistency: {
      a_recall_stddev: a.detection.recall.stddev,
      b_recall_stddev: b.detection.recall.stddev,
    },
    regressions: {
      new_missed_deals: newMissedDeals,
      new_missed_scams: newMissedScams,
      category_regressions: categoryRegressions,
    },
    pass_fail: passFail,
  };

  const fmt = (d) => `${d > 0 ? '+' : ''}${d}`;
  console.log(`[eval-compare] verdict: ${passFail.verdict}`);
  console.log(`[eval-compare] --- Detection ---`);
  console.log(
    `[eval-compare] recall:    ${comparison.recall.a} → ${comparison.recall.b} (${fmt(comparison.recall.delta)})`,
  );
  console.log(
    `[eval-compare] precision: ${comparison.precision.a} → ${comparison.precision.b} (${fmt(comparison.precision.delta)})`,
  );
  console.log(
    `[eval-compare] f2:        ${comparison.f2.a} → ${comparison.f2.b} (${fmt(comparison.f2.delta)})`,
  );
  console.log(`[eval-compare] --- Sub-metrics ---`);
  console.log(
    `[eval-compare] category:  ${comparison.category_accuracy.a} → ${comparison.category_accuracy.b} (${fmt(comparison.category_accuracy.delta)})`,
  );
  console.log(
    `[eval-compare] urgency:   ${comparison.score_in_range.a} → ${comparison.score_in_range.b} (${fmt(comparison.score_in_range.delta)})`,
  );
  console.log(
    `[eval-compare] scam:      ${comparison.scam_detection.a} → ${comparison.scam_detection.b} (${fmt(comparison.scam_detection.delta)})`,
  );
  console.log(
    `[eval-compare] cost:      $${costComparison.a} → $${costComparison.b} (${fmt(costComparison.delta)})`,
  );
  console.log(`[eval-compare] --- Per Category ---`);
  for (const [cat, data] of Object.entries(perCategoryComparison)) {
    console.log(
      `[eval-compare] ${cat}: ${data.a} → ${data.b} (${fmt(data.delta)}) [${data.a_count} threads]`,
    );
  }
  if (newMissedDeals.length > 0)
    console.log(`[eval-compare] NEW MISSED DEALS: ${newMissedDeals.join(', ')}`);

  return result
}

/**
 * Orchestrator that claims and processes filter batches concurrently
 * until all pending work is exhausted.
 *
 * Composes claim logic (inline) with the filter worker and runs them
 * through a concurrent pool.
 */
async function runFilterPipeline() {
  const authUrl = coreExports.getInput('auth-url');
  const authSecret = coreExports.getInput('auth-secret');
  const apiUrl = coreExports.getInput('api-url');
  const biscuit = coreExports.getInput('biscuit');
  const schema = sanitizeSchema(coreExports.getInput('schema'));
  const contentFetcherUrl = coreExports.getInput('content-fetcher-url');
  const emailProvider = coreExports.getInput('email-provider') || 'content-fetcher';
  const emailServiceUrl = coreExports.getInput('email-service-url');
  const maxConcurrent = parseInt(coreExports.getInput('max-concurrent') || '5', 10);
  const batchSize = parseInt(coreExports.getInput('filter-batch-size') || '200', 10);
  const maxRetries = parseInt(coreExports.getInput('max-retries') || '6', 10);
  const chunkSize = parseInt(coreExports.getInput('chunk-size') || '50', 10);
  const fetchTimeoutMs = parseInt(coreExports.getInput('fetch-timeout-ms') || '30000', 10);

  console.log(
    `[run-filter-pipeline] starting (maxConcurrent=${maxConcurrent}, batchSize=${batchSize}, maxRetries=${maxRetries}, chunkSize=${chunkSize}, fetchTimeoutMs=${fetchTimeoutMs})`,
  );

  // 1. Authenticate to SxT once at start
  const jwt = await authenticate(authUrl, authSecret);

  // 2. Create bound exec helpers
  const exec = (sql) => executeSql(apiUrl, jwt, biscuit, sql);
  const execNoRL = (sql) => executeSql(apiUrl, jwt, biscuit, sql, { skipRateLimit: true });

  // Accumulate totals across all batches
  let totalFiltered = 0;
  let totalRejected = 0;

  let batchCount = 0;
  const runStart = Date.now();

  // 3. Define claimBatch() inline
  async function claimBatch() {
    const batchId = v7();
    const claimStart = Date.now();

    // Atomically claim pending rows
    await exec(dealStates.claimFilterBatch(schema, batchId, batchSize));

    // SELECT the claimed rows
    const rows = await exec(dealStates.selectEmailsByBatch(schema, batchId));

    const count = rows ? rows.length : 0;
    const claimMs = Date.now() - claimStart;
    batchCount++;
    console.log(`[run-filter-pipeline] claimed ${count} pending rows (claimMs=${claimMs}, batch #${batchCount})`);

    // If claimed > 0, insert batch event and return
    if (count > 0) {
      await insertBatchEvent(exec, schema, {
        triggerHash: batchId,
        batchId,
        batchType: 'filter',
        eventType: 'new',
      });

      return { batch_id: batchId, count, attempts: 0, rows }
    }

    // No pending rows — look for stuck batches (filtering >5min, attempts < maxRetries)
    console.log(`[run-filter-pipeline] no pending rows, checking for stuck batches`);

    const stuckBatches = await exec(
      dealStates.findStuckBatches(schema, STATUS.FILTERING, 5, maxRetries),
    );

    if (!stuckBatches || stuckBatches.length === 0) {
      console.log(`[run-filter-pipeline] no stuck batches found, nothing to do`);
      return null
    }

    // Re-claim the stuck batch
    const stuckBatchId = stuckBatches[0].BATCH_ID;
    const attempts = stuckBatches[0].ATTEMPTS;

    console.log(
      `[run-filter-pipeline] re-claiming stuck batch ${stuckBatchId} (attempts=${attempts})`,
    );

    // SELECT its rows
    const stuckRows = await exec(dealStates.selectEmailsByBatch(schema, stuckBatchId));

    // UPDATE UPDATED_AT to prevent other instances from grabbing it
    await exec(dealStates.refreshBatchTimestamp(schema, stuckBatchId));

    // Insert batch event with retrigger type and new trigger hash
    const triggerHash = v7();
    await insertBatchEvent(exec, schema, {
      triggerHash,
      batchId: stuckBatchId,
      batchType: 'filter',
      eventType: 'retrigger',
    });

    const stuckCount = stuckRows ? stuckRows.length : 0;

    return { batch_id: stuckBatchId, count: stuckCount, attempts, rows: stuckRows }
  }

  // 4. Define processFilterBatch — the per-batch worker
  async function processFilterBatch(batch) {
    const { batch_id, rows } = batch;
    const batchStart = Date.now();

    console.log(`[run-filter-pipeline] processing batch ${batch_id} (${rows.length} rows)`);

    // Acquire rate limit tokens in bulk (2 UPDATEs + 1 batch event)
    let t0 = Date.now();
    await acquireRateLimitToken(3);
    const rlMs = Date.now() - t0;

    // a. Build metaByMessageId Map from batch.rows
    const metaByMessageId = new Map(rows.map((r) => [r.MESSAGE_ID, r]));
    const userId = rows[0].USER_ID;
    const syncStateId = rows[0].SYNC_STATE_ID;
    const messageIds = rows.map((r) => r.MESSAGE_ID);

    // b. Call fetchEmails() with format: 'metadata'
    t0 = Date.now();
    const emails = await fetchEmails(messageIds, metaByMessageId, {
      contentFetcherUrl,
      emailProvider,
      emailServiceUrl,
      userId,
      syncStateId,
      chunkSize,
      fetchTimeoutMs,
      format: 'metadata',
    });
    const fetchMs = Date.now() - t0;

    // c. Apply isRejected() to each email
    const filteredIds = [];
    const rejectedIds = [];

    for (const email of emails) {
      if (isRejected(email)) {
        rejectedIds.push(email.id);
      } else {
        filteredIds.push(email.id);
      }
    }

    console.log(
      `[run-filter-pipeline] batch ${batch_id}: ${filteredIds.length} passed, ${rejectedIds.length} rejected`,
    );

    // d. UPDATE passed IDs -> pending_classification
    t0 = Date.now();
    if (filteredIds.length > 0) {
      const quotedIds = filteredIds.map((id) => `'${sanitizeId(id)}'`);
      await execNoRL(
        dealStates.updateStatusByIds(schema, quotedIds, STATUS.PENDING_CLASSIFICATION),
      );
    }

    // e. UPDATE rejected IDs -> filter_rejected
    if (rejectedIds.length > 0) {
      const quotedIds = rejectedIds.map((id) => `'${sanitizeId(id)}'`);
      await execNoRL(dealStates.updateStatusByIds(schema, quotedIds, STATUS.FILTER_REJECTED));
    }
    const writeMs = Date.now() - t0;

    // f. Insert BATCH_EVENTS with eventType: 'complete'
    await insertBatchEvent(execNoRL, schema, {
      triggerHash: batch_id,
      batchId: batch_id,
      batchType: 'filter',
      eventType: 'complete',
    });

    const totalMs = Date.now() - batchStart;
    console.log(
      `[run-filter-pipeline] batch ${batch_id} done: totalMs=${totalMs} fetchMs=${fetchMs} writeMs=${writeMs} rlMs=${rlMs} rows=${rows.length}`,
    );

    // g. Accumulate totals
    totalFiltered += filteredIds.length;
    totalRejected += rejectedIds.length;
  }

  // 5. Dead-letter: persist failed status when pool gives up on a batch
  async function onDeadLetter(batch) {
    const bid = batch.batch_id;
    if (!bid) return
    const safeBid = sanitizeId(bid);
    await execNoRL(
      dealStates.updateStatusByBatch(schema, safeBid, STATUS.FILTERING, STATUS.FAILED),
    );
    await insertBatchEvent(execNoRL, schema, {
      triggerHash: v7(),
      batchId: bid,
      batchType: 'filter',
      eventType: 'dead_letter',
    });
    console.log(`[run-filter-pipeline] dead-lettered batch ${bid} → status=failed`);
  }

  const poolResults = await runPool(claimBatch, processFilterBatch, {
    maxConcurrent,
    maxRetries,
    onDeadLetter,
  });

  // 6. Sweep: DB rows stuck in filtering with exhausted retrigger attempts (Explorer had "nothing to process" but SxT still had leftovers)
  const stuckFailed = await sweepStuckRows(exec, schema, {
    activeStatus: STATUS.FILTERING,
    batchType: 'filter',
    maxRetries,
  });

  const runMs = Date.now() - runStart;
  logSqlStats();
  console.log(
    `[run-filter-pipeline] done — batches_processed=${poolResults.processed}, batches_failed=${poolResults.failed}, total_filtered=${totalFiltered}, total_rejected=${totalRejected}, stuck_failed=${stuckFailed}, runMs=${runMs}`,
  );

  return {
    batches_processed: poolResults.processed,
    batches_failed: poolResults.failed,
    total_filtered: totalFiltered,
    total_rejected: totalRejected,
    stuck_failed: stuckFailed,
  }
}

/**
 * WriteBatcher — collects SQL write operations from concurrent workers
 * and flushes them in combined statements to reduce SxT API calls.
 *
 * Each queue is independent. Workers await push*() which resolves once
 * the items have been flushed (or rejects on flush error).
 */


class WriteBatcher {
  /**
   * @param {Function} executeSqlFn — bound (sql) => executeSql(apiUrl, jwt, biscuit, sql)
   * @param {string} schema — sanitized schema name
   * @param {object} opts
   * @param {number} opts.flushIntervalMs — timer-based flush interval (default 5000)
   * @param {number} opts.flushThreshold — count-based flush threshold per queue (default 10)
   */
  constructor(
    executeSqlFn,
    schema,
    { flushIntervalMs = 5000, flushThreshold = 10, coreSchema = 'EMAIL_CORE_STAGING' } = {},
  ) {
    this._executeSqlFn = executeSqlFn;
    this._schema = schema;
    this._coreSchema = coreSchema;
    this._flushThreshold = flushThreshold;

    // Each queue: { items: [], waiters: [] }
    this._queues = {
      evals: { items: [], waiters: [] },
      dealDeletes: { items: [], waiters: [] },
      deals: { items: [], waiters: [] },
      contactDeletes: { items: [], waiters: [] },
      contacts: { items: [], waiters: [] },
      coreContacts: { items: [], waiters: [] },
      stateUpdates: { items: [], waiters: [] },
      batchEvents: { items: [], waiters: [] },
    };

    this._timer = setInterval(() => this._flushAll(), flushIntervalMs);
  }

  // ===========================================================
  // Push methods
  // ===========================================================

  /** Push pre-built VALUES strings for EMAIL_THREAD_EVALUATIONS upsert */
  pushEvals(rows) {
    return this._push('evals', rows)
  }

  /** Push sanitized thread IDs for DEALS delete */
  pushDealDeletes(threadIds) {
    return this._push('dealDeletes', threadIds)
  }

  /** Push pre-built VALUES strings for DEALS upsert */
  pushDeals(rows) {
    return this._push('deals', rows)
  }

  /** Push sanitized deal IDs for DEAL_CONTACTS delete */
  pushContactDeletes(dealIds) {
    return this._push('contactDeletes', dealIds)
  }

  /** Push pre-built VALUES strings for DEAL_CONTACTS insert */
  pushContacts(rows) {
    return this._push('contacts', rows)
  }

  /** Push pre-built VALUES strings for core contacts upsert (COALESCE ON CONFLICT) */
  pushCoreContacts(rows) {
    return this._push('coreContacts', rows)
  }

  /**
   * Push state update IDs.
   * @param {string[]} dealEmailIds — email metadata IDs for 'deal' status
   * @param {string[]} notDealEmailIds — email metadata IDs for 'not_deal' status
   */
  pushStateUpdates(dealEmailIds, notDealEmailIds) {
    return this._push('stateUpdates', [{ dealEmailIds, notDealEmailIds }])
  }

  /** Push pre-built VALUES strings for BATCH_EVENTS upsert */
  pushBatchEvents(rows) {
    return this._push('batchEvents', rows)
  }

  // ===========================================================
  // Lifecycle
  // ===========================================================

  /** Flush all pending queues and clear the timer. Called at pipeline end. Loops until all queues are empty. */
  async drain() {
    clearInterval(this._timer);
    let hasItems = true;
    while (hasItems) {
      await this._flushAll();
      hasItems = Object.values(this._queues).some((q) => q.items.length > 0);
    }
  }

  /** Clear the timer without flushing. Rejects all pending waiters. For cleanup on fatal error. */
  stop() {
    clearInterval(this._timer);
    const err = new Error('WriteBatcher stopped');
    for (const queue of Object.values(this._queues)) {
      const waiters = queue.waiters;
      queue.waiters = [];
      queue.items = [];
      for (const w of waiters) w.reject(err);
    }
  }

  // ===========================================================
  // Internal
  // ===========================================================

  /**
   * Add items to a queue, register a waiter, and trigger flush if threshold met.
   * @returns {Promise<void>} resolves when the items have been flushed
   */
  _push(queueName, items) {
    const queue = this._queues[queueName];
    queue.items.push(...items);

    const promise = new Promise((resolve, reject) => {
      queue.waiters.push({ resolve, reject });
    });

    if (queue.items.length >= this._flushThreshold) {
      this._flushQueue(queueName);
    }

    return promise
  }

  /** Flush all queues that have pending items */
  async _flushAll() {
    const promises = [];
    for (const name of Object.keys(this._queues)) {
      if (this._queues[name].items.length > 0) {
        promises.push(this._flushQueue(name));
      }
    }
    await Promise.all(promises);
  }

  /** Flush a single queue */
  async _flushQueue(queueName) {
    const queue = this._queues[queueName];

    // Swap out items and waiters atomically
    const items = queue.items;
    const waiters = queue.waiters;
    queue.items = [];
    queue.waiters = [];

    if (items.length === 0) return

    console.log(`[batcher] flushing ${queueName}: ${items.length} items`);

    try {
      await this._executeQueue(queueName, items);
      for (const w of waiters) w.resolve();
    } catch (err) {
      console.error(`[batcher] ${queueName} flush failed (${items.length} items): ${err.message}`);
      // If combined flush fails, try each item individually to isolate the bad one
      if (items.length > 1 && err.message.includes('SxT 400')) {
        console.error(
          `[batcher] combined ${queueName} flush failed, falling back to individual items`,
        );
        for (let i = 0; i < items.length; i++) {
          try {
            await this._executeQueue(queueName, [items[i]]);
          } catch (itemErr) {
            console.error(`[batcher] ${queueName} item ${i} failed: ${itemErr.message}`);
          }
        }
        // Resolve all waiters — individual items that succeeded are written,
        // failed items are logged and skipped
        for (const w of waiters) w.resolve();
      } else {
        for (const w of waiters) w.reject(err);
      }
    }
  }

  /** Build and execute SQL for a given queue */
  async _executeQueue(queueName, items) {
    const s = this._schema;

    switch (queueName) {
      case 'evals': {
        await this._executeSqlFn(evaluations.upsert(s, items));
        break
      }

      case 'dealDeletes': {
        await this._executeSqlFn(deals.deleteByThreadIds(s, items));
        break
      }

      case 'deals': {
        await this._executeSqlFn(deals.upsert(s, items));
        break
      }

      case 'contactDeletes': {
        await this._executeSqlFn(dealContacts.deleteByDealIds(s, items));
        break
      }

      case 'contacts': {
        await this._executeSqlFn(dealContacts.upsert(s, items));
        break
      }

      case 'coreContacts': {
        // Dedup by (USER_ID, EMAIL) — concurrent workers may push the same contact
        const dedupMap = new Map();
        for (const item of items) {
          const m = item.match(/^\('([^']*(?:''[^']*)*)',\s*'([^']*(?:''[^']*)*)'/);
          const key = m ? `${m[1]}|${m[2]}` : item;
          dedupMap.set(key, item); // last write wins
        }
        const uniqueItems = [...dedupMap.values()];
        if (uniqueItems.length < items.length) {
          console.log(`[batcher] coreContacts deduped: ${items.length} → ${uniqueItems.length}`);
        }
        const cs = this._coreSchema;
        await this._executeSqlFn(contacts.upsert(cs, uniqueItems));
        break
      }

      case 'stateUpdates': {
        // Merge all stateUpdate items into combined ID lists
        const allDealIds = [];
        const allNotDealIds = [];
        for (const item of items) {
          allDealIds.push(...item.dealEmailIds);
          allNotDealIds.push(...item.notDealEmailIds);
        }
        if (allDealIds.length > 0) {
          await this._executeSqlFn(dealStates.updateStatusByIds(s, allDealIds, STATUS.DEAL));
        }
        if (allNotDealIds.length > 0) {
          await this._executeSqlFn(
            dealStates.updateStatusByIds(s, allNotDealIds, STATUS.NOT_DEAL),
          );
        }
        break
      }

      case 'batchEvents': {
        await this._executeSqlFn(batchEvents.upsertBulk(s, items));
        break
      }
    }
  }
}

/**
 * Orchestrator that claims and processes classify batches concurrently,
 * with in-memory audit passing through eval upserts, deal upserts,
 * contact inserts, and terminal state updates.
 */
async function runClassifyPipeline() {
  const authUrl = coreExports.getInput('auth-url');
  const authSecret = coreExports.getInput('auth-secret');
  const apiUrl = coreExports.getInput('api-url');
  const biscuit = coreExports.getInput('biscuit');
  const schema = sanitizeSchema(coreExports.getInput('schema'));
  const coreSchema = sanitizeSchema(coreExports.getInput('email_core_schema') || 'EMAIL_CORE_STAGING');
  const contentFetcherUrl = coreExports.getInput('content-fetcher-url');
  const emailProvider = coreExports.getInput('email-provider') || 'content-fetcher';
  const emailServiceUrl = coreExports.getInput('email-service-url');
  const hyperbolicKey = coreExports.getInput('hyperbolic-key');
  const primaryModel = coreExports.getInput('primary-model') || 'Qwen/Qwen3-235B-A22B-Instruct-2507';
  const fallbackModel = coreExports.getInput('fallback-model') || 'deepseek-ai/DeepSeek-V3';
  const aiApiUrl = coreExports.getInput('ai-api-url') || 'https://api.hyperbolic.xyz/v1/chat/completions';
  const maxConcurrent = parseInt(coreExports.getInput('max-concurrent') || '70', 10);
  const classifyBatchSize = parseInt(coreExports.getInput('classify-batch-size') || '5', 10);
  const maxRetries = parseInt(coreExports.getInput('max-retries') || '6', 10);
  const chunkSize = parseInt(coreExports.getInput('chunk-size') || '10', 10);
  const fetchTimeoutMs = parseInt(coreExports.getInput('fetch-timeout-ms') || '120000', 10);
  const flushIntervalMs = parseInt(coreExports.getInput('flush-interval-ms') || '5000', 10);
  const flushThreshold = parseInt(coreExports.getInput('flush-threshold') || '5', 10);

  console.log(
    `[run-classify-pipeline] starting (maxConcurrent=${maxConcurrent}, batchSize=${classifyBatchSize}, maxRetries=${maxRetries}, chunkSize=${chunkSize}, fetchTimeoutMs=${fetchTimeoutMs})`,
  );

  // 1. Authenticate to SxT once at start
  const jwt = await authenticate(authUrl, authSecret);

  // 2. Create bound exec helpers
  const exec = (sql) => executeSql(apiUrl, jwt, biscuit, sql);
  const execNoRL = (sql) => executeSql(apiUrl, jwt, biscuit, sql, { skipRateLimit: true });

  // 3. Create write batcher (uses execNoRL — tokens acquired in bulk by workers)
  const batcher = new WriteBatcher(execNoRL, schema, {
    flushIntervalMs,
    flushThreshold,
    coreSchema,
  });

  // =========================================================================
  //  CLAIM FUNCTION (inline, same pattern as claim-classify-batch)
  // =========================================================================

  async function claimBatch() {
    const claimStart = Date.now();
    const batchId = v7();

    // Atomic UPDATE for pending_classification threads (thread-aware, NOT EXISTS for pending/filtering)
    await exec(dealStates.claimClassifyBatch(schema, batchId, classifyBatchSize));

    // SELECT the claimed rows
    const rows = await exec(dealStates.selectEmailsWithEvalAndCreator(schema, batchId));

    const count = rows ? rows.length : 0;
    console.log(`[run-classify-pipeline] claimed ${count} pending rows in ${Date.now() - claimStart}ms`);

    // If claimed > 0, insert batch event and return
    if (count > 0) {
      await insertBatchEvent(exec, schema, {
        triggerHash: batchId,
        batchId,
        batchType: 'classify',
        eventType: 'new',
      });

      return { batch_id: batchId, count, attempts: 0, rows }
    }

    // No pending rows — look for stuck batches (classifying >5min, attempts < maxRetries)
    console.log(`[run-classify-pipeline] no pending rows, checking for stuck batches`);

    const stuckBatches = await exec(
      dealStates.findStuckBatches(schema, STATUS.CLASSIFYING, 5, maxRetries),
    );

    if (!stuckBatches || stuckBatches.length === 0) {
      console.log(`[run-classify-pipeline] no stuck batches found, nothing to do`);
      return null
    }

    // Re-claim the stuck batch
    const stuckBatchId = stuckBatches[0].BATCH_ID;
    const attempts = parseInt(stuckBatches[0].ATTEMPTS, 10);

    console.log(
      `[run-classify-pipeline] re-claiming stuck batch ${stuckBatchId} (attempts=${attempts})`,
    );

    // SELECT its rows
    const stuckRows = await exec(dealStates.selectEmailsWithEvalAndCreator(schema, stuckBatchId));

    // UPDATE UPDATED_AT to prevent other instances from grabbing it
    await exec(dealStates.refreshBatchTimestamp(schema, stuckBatchId));

    // Insert batch event with retrigger type and new trigger hash
    const triggerHash = v7();
    await insertBatchEvent(exec, schema, {
      triggerHash,
      batchId: stuckBatchId,
      batchType: 'classify',
      eventType: 'retrigger',
    });

    const stuckCount = stuckRows ? stuckRows.length : 0;

    return { batch_id: stuckBatchId, count: stuckCount, attempts, rows: stuckRows }
  }

  // =========================================================================
  //  WORKER FUNCTION — does ALL steps per batch
  // =========================================================================

  async function processClassifyBatch(batch) {
    const { batch_id: batchId, rows } = batch;
    const creatorEmail = rows[0].CREATOR_EMAIL || '';
    const alreadyEvaluatedThreadIds = new Set();
    const batchStart = Date.now();
    const timings = {};

    console.log(`[run-classify-pipeline] processing batch ${batchId} (${rows.length} rows)`);

    // Acquire rate limit tokens in bulk for this batch attempt
    // ~2 individual SQL calls (audit check + audit insert) — batcher handles the rest
    let t0 = Date.now();
    await acquireRateLimitToken(2);
    timings.rateLimit = Date.now() - t0;

    // -----------------------------------------------------------------------
    // Step 2: Get or create audit — check for existing audit (retry case)
    // -----------------------------------------------------------------------

    let threads = null;

    t0 = Date.now();
    const existingAudit = await execNoRL(audits.selectByBatch(schema, batchId));

    if (existingAudit && existingAudit.length > 0 && existingAudit[0].AI_EVALUATION) {
      try {
        const parsed = JSON.parse(existingAudit[0].AI_EVALUATION);
        threads = parsed.threads || parsed || [];
        console.log(
          `[run-classify-pipeline] audit exists for ${batchId} — using cached (${threads.length} threads)`,
        );
      } catch {
        console.log(`[run-classify-pipeline] existing audit has invalid JSON, re-running AI`);
      }
    }

    // -----------------------------------------------------------------------
    // Step 3: AI classification (only if no existing audit)
    // -----------------------------------------------------------------------

    let modelUsed = primaryModel;

    timings.auditCheck = Date.now() - t0;

    if (!threads) {
      // a. Fetch email content via fetchEmails() (NO format param = full content)
      const metaByMessageId = new Map(rows.map((r) => [r.MESSAGE_ID, r]));
      const userId = rows[0].USER_ID;
      const syncStateId = rows[0].SYNC_STATE_ID;
      const messageIds = rows.map((r) => r.MESSAGE_ID);

      let allEmails;
      t0 = Date.now();
      try {
        allEmails = await fetchEmails(messageIds, metaByMessageId, {
          contentFetcherUrl,
          emailProvider,
          emailServiceUrl,
          userId,
          syncStateId,
          chunkSize,
          fetchTimeoutMs,
        });
      } catch {
        allEmails = [];
      }
      timings.fetch = Date.now() - t0;
      console.log(
        `[run-classify-pipeline] batch ${batchId}: fetched ${allEmails.length}/${messageIds.length} emails in ${timings.fetch}ms`,
      );

      // Handle unfetchable threads — threads with zero emails returned
      const fetchedThreadIds = new Set(allEmails.map((e) => e.threadId).filter(Boolean));
      const allBatchThreadIds = [...new Set(rows.map((r) => r.THREAD_ID))];
      const unfetchableThreadIds = allBatchThreadIds.filter((tid) => !fetchedThreadIds.has(tid));

      if (unfetchableThreadIds.length > 0) {
        console.log(
          `[run-classify-pipeline] ${unfetchableThreadIds.length} unfetchable threads, checking previous evaluations`,
        );

        // Look up existing evaluations for unfetchable threads
        const quotedUnfetchable = unfetchableThreadIds.map((id) => `'${sanitizeId(id)}'`);
        const existingEvals = await execNoRL(evaluations.selectByThreadIds(schema, quotedUnfetchable));
        const evalByThread = {};
        for (const e of existingEvals || []) {
          evalByThread[e.THREAD_ID] = e.IS_DEAL;
        }

        // Mark unfetchable rows based on previous eval or default to not_deal
        const unfetchableDealIds = [];
        const unfetchableNotDealIds = [];
        for (const tid of unfetchableThreadIds) {
          const threadRows = rows.filter((r) => r.THREAD_ID === tid);
          const emailIds = threadRows.map((r) => r.EMAIL_METADATA_ID);
          const wasDeal = evalByThread[tid] === true || evalByThread[tid] === 'true';
          if (wasDeal) {
            unfetchableDealIds.push(...emailIds);
          } else {
            unfetchableNotDealIds.push(...emailIds);
          }
        }

        if (unfetchableDealIds.length > 0) {
          const quotedDealIds = unfetchableDealIds.map((id) => `'${sanitizeId(id)}'`);
          await execNoRL(dealStates.updateStatusByIds(schema, quotedDealIds, STATUS.DEAL));
          console.log(
            `[run-classify-pipeline] ${unfetchableDealIds.length} unfetchable rows → deal (previous eval)`,
          );
        }
        if (unfetchableNotDealIds.length > 0) {
          const quotedNotDealIds = unfetchableNotDealIds.map((id) => `'${sanitizeId(id)}'`);
          await execNoRL(dealStates.updateStatusByIds(schema, quotedNotDealIds, STATUS.NOT_DEAL));
          console.log(
            `[run-classify-pipeline] ${unfetchableNotDealIds.length} unfetchable rows → not_deal`,
          );
        }
      }

      // ---------------------------------------------------------------
      // Already-evaluated skip: threads with existing deals + no newer emails
      // ---------------------------------------------------------------

      const remainingThreadIds = [...new Set(allEmails.map((e) => e.threadId).filter(Boolean))];

      if (remainingThreadIds.length > 0) {
        const quotedFetched = remainingThreadIds.map((id) => `'${sanitizeId(id)}'`);
        const existingDeals = await execNoRL(deals.selectByThreadIds(schema, quotedFetched));

        if (existingDeals && existingDeals.length > 0) {
          const dealByThread = {};
          for (const d of existingDeals) {
            dealByThread[d.THREAD_ID] = d.UPDATED_AT;
          }

          // Group emails by thread and find latest date per thread
          const emailsByThread = {};
          for (const email of allEmails) {
            if (!email.threadId) continue
            if (!emailsByThread[email.threadId]) emailsByThread[email.threadId] = [];
            emailsByThread[email.threadId].push(email);
          }

          const skippedEmailIds = [];
          const skippedThreadIds = [];

          for (const [threadId, dealUpdatedAt] of Object.entries(dealByThread)) {
            const threadEmails = emailsByThread[threadId];
            if (!threadEmails || threadEmails.length === 0) continue

            const emailDates = threadEmails
              .map((e) => new Date(e.date))
              .filter((d) => !isNaN(d.getTime()));

            // No valid dates — can't determine, classify normally
            if (emailDates.length === 0) continue

            const latestEmailDate = emailDates.reduce(
              (latest, d) => (d > latest ? d : latest),
              new Date(0),
            );

            if (latestEmailDate <= new Date(dealUpdatedAt)) {
              // All emails are older than the deal — skip classification
              alreadyEvaluatedThreadIds.add(threadId);
              skippedThreadIds.push(threadId);
              const threadRows = rows.filter((r) => r.THREAD_ID === threadId);
              skippedEmailIds.push(...threadRows.map((r) => r.EMAIL_METADATA_ID));
              // Remove these emails from allEmails so they don't go to AI
              allEmails = allEmails.filter((e) => e.threadId !== threadId);
            }
          }

          if (skippedEmailIds.length > 0) {
            const quotedSkipped = skippedEmailIds.map((id) => `'${sanitizeId(id)}'`);
            await execNoRL(dealStates.updateStatusByIds(schema, quotedSkipped, STATUS.DEAL));
            console.log(
              `[run-classify-pipeline] ${skippedEmailIds.length} rows skipped → deal (already evaluated, ${skippedThreadIds.length} threads)`,
            );
          }
        }
      }

      if (allEmails.length === 0) {
        console.log(`[run-classify-pipeline] no emails to classify, skipping AI`);
        await batcher.pushBatchEvents([
          `('${batchId}', '${batchId}', 'classify', 'complete', CURRENT_TIMESTAMP)`,
        ]);
        console.log(`[run-classify-pipeline] batch ${batchId} complete (no emails to classify)`);
        return
      }

      // b. Build prompt via buildPrompt(emails)
      t0 = Date.now();
      const { systemPrompt, userPrompt, threadOrder } = buildPrompt(allEmails, { creatorEmail });

      // c. 4-layer AI resilience pipeline
      const aiOpts = { apiUrl: aiApiUrl, apiKey: hyperbolicKey };

      const classifyMessages = [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt },
      ];

      // --- Layer 0: Primary model call ---
      let primaryRaw;
      const aiStart = Date.now();
      try {
        const result = await callModel(primaryModel, classifyMessages, {
          temperature: 0,
          ...aiOpts,
        });
        primaryRaw = result.content;
        timings.primaryModel = Date.now() - aiStart;
        console.log(`[run-classify-pipeline] batch ${batchId}: primary model responded in ${timings.primaryModel}ms`);
      } catch (primaryApiError) {
        timings.primaryModel = Date.now() - aiStart;
        console.log(`[run-classify-pipeline] Primary model API failed after ${timings.primaryModel}ms: ${primaryApiError.message}`);
        primaryRaw = null;
      }

      if (primaryRaw) {
        // --- Layer 1: Local JSON repair ---
        try {
          threads = parseAndValidate(primaryRaw, threadOrder);
          console.log(`[run-classify-pipeline] Primary model succeeded: ${threads.length} threads`);
        } catch (parseError) {
          console.log(`[run-classify-pipeline] Primary JSON parse failed: ${parseError.message}`);

          // --- Layer 2: Corrective retry (same model, send broken output back) ---
          try {
            const correctiveStart = Date.now();
            console.log(`[run-classify-pipeline] Attempting corrective retry with ${primaryModel}`);
            const correctiveMessages = [
              ...classifyMessages,
              { role: 'assistant', content: primaryRaw },
              {
                role: 'user',
                content: `Your previous classification response could not be parsed as valid JSON.\n\nParse error:\n${parseError.message}\n\nPlease return the corrected classification as a valid JSON array. Fix only the JSON formatting issue. Do not change any classification decisions. Return ONLY the JSON array with no other text.`,
              },
            ];
            const corrected = await callModel(primaryModel, correctiveMessages, {
              temperature: 0,
              ...aiOpts,
            });
            const correctedRaw = corrected.content;
            threads = parseAndValidate(correctedRaw, threadOrder);
            modelUsed = `${primaryModel}(corrective-retry)`;
            timings.correctiveRetry = Date.now() - correctiveStart;
            console.log(
              `[run-classify-pipeline] Corrective retry succeeded in ${timings.correctiveRetry}ms: ${threads.length} threads`,
            );
          } catch (correctiveError) {
            console.log(
              `[run-classify-pipeline] Corrective retry failed: ${correctiveError.message}`,
            );
          }
        }
      }

      // --- Layer 3: Fallback model ---
      if (!threads) {
        const fallbackStart = Date.now();
        console.log(`[run-classify-pipeline] Falling back to ${fallbackModel}`);
        modelUsed = fallbackModel;
        try {
          const fallbackResult = await callModel(fallbackModel, classifyMessages, {
            temperature: 0.6,
            ...aiOpts,
          });
          const fallbackRaw = fallbackResult.content;
          threads = parseAndValidate(fallbackRaw, threadOrder);
          timings.fallbackModel = Date.now() - fallbackStart;
          console.log(`[run-classify-pipeline] Fallback model succeeded in ${timings.fallbackModel}ms: ${threads.length} threads`);
        } catch (fallbackError) {
          console.error(
            `[run-classify-pipeline] All layers exhausted. Primary and fallback both failed.`,
          );
          throw new Error(
            `Classification failed: primary and fallback models both returned no valid JSON. Last error: ${fallbackError.message}`,
          )
        }
      }

      timings.aiTotal = Date.now() - t0;

      // d. Save audit checkpoint
      t0 = Date.now();
      const auditId = v7();
      const aiOutput = { threads };
      const evaluation = sanitizeString(JSON.stringify(aiOutput));
      try {
        await execNoRL(
          audits.insert(schema, {
            id: auditId,
            batchId,
            threadCount: threads.length,
            emailCount: rows.length,
            cost: 0,
            inputTokens: 0,
            outputTokens: 0,
            model: modelUsed,
            evaluation,
          }),
        );
        timings.auditSave = Date.now() - t0;
        console.log(`[run-classify-pipeline] audit saved: ${auditId} (model: ${modelUsed}) in ${timings.auditSave}ms`);
      } catch (err) {
        if (
          err.message.includes('integrity constraint') ||
          err.message.includes('unique') ||
          err.message.includes('duplicate')
        ) {
          console.log(
            `[run-classify-pipeline] audit already exists for batch (concurrent run), continuing`,
          );
        } else {
          throw err
        }
      }
    }

    // -----------------------------------------------------------------------
    // Step 4: Save evals via batcher
    // -----------------------------------------------------------------------

    t0 = Date.now();
    const evalValues = threads.map((thread) => {
      const threadId = sanitizeId(thread.thread_id);
      return `('${v7()}', '${threadId}', '', '${sanitizeString(thread.category || '')}', '${sanitizeString(thread.ai_summary || '')}', ${thread.is_deal ? 'true' : 'false'}, ${(thread.category || '').toLowerCase() === 'likely_scam' ? 'true' : 'false'}, ${typeof thread.ai_score === 'number' ? thread.ai_score : 0}, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)`
    });

    await batcher.pushEvals(evalValues);

    console.log(`[run-classify-pipeline] upserted ${threads.length} thread evaluations`);

    // -----------------------------------------------------------------------
    // Step 5: Save deals via batcher
    // -----------------------------------------------------------------------

    // Build userByThread map from batch rows
    const userByThread = {};
    for (const row of rows) {
      userByThread[row.THREAD_ID] = row.USER_ID;
    }

    // Separate deal vs non-deal threads
    const dealThreads = [];
    const notDealThreadIds = [];

    for (const thread of threads) {
      if (thread.is_deal) {
        dealThreads.push(thread);
      } else {
        notDealThreadIds.push(sanitizeId(thread.thread_id));
      }
    }

    // Batch DELETE non-deal threads via batcher
    if (notDealThreadIds.length > 0) {
      const quoted = notDealThreadIds.map((id) => `'${id}'`);
      await batcher.pushDealDeletes(quoted);
      console.log(`[run-classify-pipeline] deleted ${notDealThreadIds.length} non-deal threads`);
    }

    // Batch upsert deals via batcher
    if (dealThreads.length > 0) {
      const dealValues = dealThreads.map((thread) => {
        const threadId = sanitizeId(thread.thread_id);
        const userId = userByThread[threadId] ? sanitizeId(userByThread[threadId]) : '';
        const dealId = threadId;
        const dealName = sanitizeString(thread.deal_name || '');
        const dealType = sanitizeString(thread.deal_type || '');
        const dealValue =
          typeof thread.deal_value === 'string' ? parseFloat(thread.deal_value) || 0 : 0;
        const currency = sanitizeString(thread.currency || 'USD');
        const brand = thread.main_contact ? sanitizeString(thread.main_contact.company || '') : '';
        const category = sanitizeString(thread.category || '');
        return `('${dealId}', '${userId}', '${threadId}', '', '${dealName}', '${dealType}', '${category}', ${dealValue}, '${currency}', '${brand}', true, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)`
      });

      await batcher.pushDeals(dealValues);

      console.log(`[run-classify-pipeline] ${dealThreads.length} deals upserted`);
    }

    // -----------------------------------------------------------------------
    // Step 6: Save deal contacts via batcher (two-table upsert)
    // -----------------------------------------------------------------------

    if (dealThreads.length > 0) {
      const coreContactValues = [];
      const dealContactValues = [];

      for (const thread of dealThreads) {
        const mc = thread.main_contact;
        if (!mc) continue
        const email = (mc.email || '').trim().toLowerCase();
        if (!email) continue

        // Skip creator's own email — AI sometimes ignores the "external only" rule
        if (creatorEmail && email === creatorEmail.trim().toLowerCase()) continue

        const threadId = sanitizeId(thread.thread_id);
        const userId = userByThread[threadId] ? sanitizeId(userByThread[threadId]) : '';
        const contactEmail = sanitizeString(email);
        const nameVal = toSqlNullable(mc.name);
        const companyVal = toSqlNullable(mc.company);
        const titleVal = toSqlNullable(mc.title);
        const phoneVal = toSqlNullable(mc.phone_number);

        // Core contacts — COALESCE preserves existing non-null values
        coreContactValues.push(
          `('${userId}', '${contactEmail}', ${nameVal}, ${companyVal}, ${titleVal}, ${phoneVal}, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)`,
        );

        // Deal contacts — simplified 4-column relationship upsert
        dealContactValues.push(
          `('${threadId}', '${userId}', '${contactEmail}', 'primary', CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)`,
        );
      }

      if (coreContactValues.length > 0) {
        try {
          await batcher.pushCoreContacts(coreContactValues);
        } catch (err) {
          console.error(
            `[run-classify-pipeline] core contacts upsert failed (non-fatal): ${err.message}`,
          );
        }
      }

      if (dealContactValues.length > 0) {
        await batcher.pushContacts(dealContactValues);
      }

      console.log(
        `[run-classify-pipeline] ${dealContactValues.length} contacts saved (core + deal)`,
      );
    }

    // -----------------------------------------------------------------------
    // Step 7: Update deal states to terminal via batcher
    // -----------------------------------------------------------------------

    // Build metadataByThread map from batch rows
    const metadataByThread = {};
    for (const row of rows) {
      if (!metadataByThread[row.THREAD_ID]) metadataByThread[row.THREAD_ID] = [];
      metadataByThread[row.THREAD_ID].push(row);
    }

    // Collect dealEmailIds and notDealEmailIds from AI results
    const dealEmailIds = [];
    const notDealEmailIds = [];
    const classifiedThreadIds = new Set();

    for (const thread of threads) {
      if (!thread.thread_id) continue
      const threadId = sanitizeId(thread.thread_id);
      classifiedThreadIds.add(threadId);
      const threadEmails = metadataByThread[threadId] || [];
      if (threadEmails.length === 0) continue

      const emailIds = threadEmails.map((e) => e.EMAIL_METADATA_ID);
      if (thread.is_deal) {
        dealEmailIds.push(...emailIds);
      } else {
        notDealEmailIds.push(...emailIds);
      }
    }

    // Handle rows whose threads weren't in the AI response
    // Use previous evaluation if exists, otherwise default to not_deal
    for (const [threadId, threadRows] of Object.entries(metadataByThread)) {
      if (classifiedThreadIds.has(threadId)) continue
      if (alreadyEvaluatedThreadIds.has(threadId)) continue
      // Already handled by unfetchable logic earlier
      if (threadRows.every((r) => r.STATUS === STATUS.DEAL || r.STATUS === STATUS.NOT_DEAL))
        continue

      const emailIds = threadRows.map((r) => r.EMAIL_METADATA_ID);
      // Check if any row has a previous eval indicating deal
      const wasDeal = threadRows.some(
        (r) => r.PREVIOUS_IS_DEAL === true || r.PREVIOUS_IS_DEAL === 'true',
      );
      if (wasDeal) {
        dealEmailIds.push(...emailIds);
        console.log(
          `[run-classify-pipeline] unclassified thread ${threadId} → deal (previous eval)`,
        );
      } else {
        notDealEmailIds.push(...emailIds);
        console.log(`[run-classify-pipeline] unclassified thread ${threadId} → not_deal (default)`);
      }
    }

    // Write state updates directly (not through batcher) to ensure they commit
    if (dealEmailIds.length > 0) {
      const quotedIds = dealEmailIds.map((id) => `'${sanitizeId(id)}'`);
      await execNoRL(dealStates.updateStatusByIds(schema, quotedIds, STATUS.DEAL));
    }
    if (notDealEmailIds.length > 0) {
      const quotedNDIds = notDealEmailIds.map((id) => `'${sanitizeId(id)}'`);
      await execNoRL(dealStates.updateStatusByIds(schema, quotedNDIds, STATUS.NOT_DEAL));
    }

    timings.dbWrites = Date.now() - t0;

    console.log(
      `[run-classify-pipeline] states: ${dealEmailIds.length} -> deal, ${notDealEmailIds.length} -> not_deal`,
    );

    // -----------------------------------------------------------------------
    // Step 8: Record completion via batcher
    // -----------------------------------------------------------------------

    await batcher.pushBatchEvents([
      `('${batchId}', '${batchId}', 'classify', 'complete', CURRENT_TIMESTAMP)`,
    ]);

    timings.total = Date.now() - batchStart;
    console.log(
      `[run-classify-pipeline] batch ${batchId} complete — timings: ${JSON.stringify(timings)}`,
    );
  }

  // =========================================================================
  //  RUN POOL
  // =========================================================================

  async function onDeadLetter(batch) {
    const bid = batch.batch_id;
    if (!bid) return
    const safeBid = sanitizeId(bid);
    await execNoRL(
      dealStates.updateStatusByBatch(schema, safeBid, STATUS.CLASSIFYING, STATUS.FAILED),
    );
    await insertBatchEvent(execNoRL, schema, {
      triggerHash: v7(),
      batchId: bid,
      batchType: 'classify',
      eventType: 'dead_letter',
    });
    console.log(`[run-classify-pipeline] dead-lettered batch ${bid} → status=failed`);
  }

  const poolResults = await runPool(claimBatch, processClassifyBatch, {
    maxConcurrent,
    maxRetries,
    onDeadLetter,
  });

  // Drain all pending writes
  await batcher.drain();

  const stuckFailed = await sweepStuckRows(exec, schema, {
    activeStatus: STATUS.CLASSIFYING,
    batchType: 'classify',
    maxRetries,
  });

  const orphanFailed = await sweepOrphanedRows(exec, schema, {
    statuses: [STATUS.PENDING_CLASSIFICATION],
    staleMinutes: 30,
  });

  console.log(
    `[run-classify-pipeline] done — batches_processed=${poolResults.processed}, batches_failed=${poolResults.failed}, stuck_failed=${stuckFailed}, orphan_failed=${orphanFailed}`,
  );

  return {
    batches_processed: poolResults.processed,
    batches_failed: poolResults.failed,
    stuck_failed: stuckFailed,
    orphan_failed: orphanFailed,
  }
}

const COMMANDS = {
  'sync-deal-states': runSyncDealStates,
  eval: runEval,
  'eval-compare': runEvalCompare,
  'run-filter-pipeline': runFilterPipeline,
  'run-classify-pipeline': runClassifyPipeline,
};

async function run() {
  let command = 'unknown';
  try {
    command = coreExports.getInput('command', { required: true });
    const handler = COMMANDS[command];
    if (!handler) {
      coreExports.setFailed(
        `Unknown command: "${command}". Available: ${Object.keys(COMMANDS).join(', ')}`,
      );
      return
    }
    console.log(`[dealsync] command=${command} starting`);
    const result = await handler();
    console.log(`[dealsync] command=${command} success`);
    coreExports.setOutput('success', 'true');
    // If result is already a string (e.g. encrypted output), don't double-stringify
    coreExports.setOutput('result', typeof result === 'string' ? result : JSON.stringify(result));
  } catch (error) {
    console.log(`[dealsync] command=${command} FAILED: ${error.message}`);
    console.log(`[dealsync] stack: ${error.stack}`);
    coreExports.setOutput('success', 'false');
    coreExports.setOutput('error', error.message);
    coreExports.setOutput('error_stack', error.stack || '');
    coreExports.setFailed(error.message);
    throw error
  }
}

run().catch(() => process.exit(1));
